import { ChangeDetectorRef, Component, OnInit, ViewChild } from "@angular/core";
import { ClientSearchComponent } from "src/app/views/components/client-search/client-search.component";
import {
  AgreementInfo,
  AgreementTransInfo,
} from "src/app/views/Models/Loan/AgreementInfo";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { pagingService } from "src/app/core/services/paging.service";

import {
  trigger,
  state,
  style,
  animate,
  transition,
} from "@angular/animations";
import { AlertService } from "src/app/core/services/alert.service";
import { IonSelect } from "@ionic/angular";
import { AgreementService } from "src/app/core/services/overdraft/agreement.service";
import {
  ApexChart,
  ApexLegend,
  ApexNonAxisChartSeries,
  ApexTooltip,
} from "ng-apexcharts";

type ChartOptions = {
  series: ApexNonAxisChartSeries;
  chart: ApexChart;
  labels: string[];
  colors: string[];
  legend: ApexLegend;
  tooltip: ApexTooltip;
};

@Component({
  selector: "app-agreement-trans-tracking",
  templateUrl: "./agreement-trans-tracking.page.html",
  styleUrls: ["./agreement-trans-tracking.page.scss"],
  animations: [
    trigger("fadeSlide", [
      state(
        "hidden",
        style({
          opacity: 0,
          transform: "translateX(-50px)", // Start position (Left side)
          display: "none",
        })
      ),
      state(
        "visible",
        style({
          opacity: 1,
          transform: "translateX(0)", // Final position
          display: "block",
        })
      ),
      transition("hidden => visible", [animate("400ms ease-out")]), // Fade in + Slide Right
      transition("visible => hidden", [animate("300ms ease-in")]), // Fade out + Slide Left
    ]),
    trigger("countAnimation", [
      transition(":increment", [
        style({ opacity: 0, transform: "translateY(-20px)" }), // Start above
        animate(
          "300ms ease-out",
          style({ opacity: 1, transform: "translateY(0)" })
        ),
      ]),
    ]),
  ],
})
export class AgreementTransTrackingPage implements OnInit {
  constructor(
    public pagingService: pagingService,
    private alertService: AlertService,
    private agreementService: AgreementService,
    private cdref: ChangeDetectorRef
  ) {}

  ngOnInit() {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
  }

  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }

  //region Variables
  ClientAgreementsResponseModal: AgreementInfo[] = [];
  ClientAgreementInfoResponseModal: AgreementInfo[] = [];
  ClientAgreementTransResponseModal: AgreementTransInfo[] = [];
  ClientAgreementTransResponseModalPaging: AgreementTransInfo[];
  selectedClient: SearchResult;
  isSearching: boolean = true;
  initialSearchType: string = "1";
  isAgreementsList: boolean = false;
  isAgreementSelected: boolean = false;
  availableCredit: number = 0;
  creditLimit: number = 0;
  usedBalance: number = 0;
  isAgreeHaveNoTrans: boolean = false;
  showLoader: boolean = false;
  agreementKey: string;
  currentTransType: number = 0;
  transViewSelectInitialValue: number = 0;
  isWithdraw: boolean = true;
  isDeposit: boolean = true;
  isDailyTrns: boolean = true;
  isCounterCard: boolean = true;
  showMoreOptions: boolean = false;
  withdrawTransCounter: number = 0;
  depositTransCounter: number = 0;
  dailyTransCounter: number = 0;
  isNotActiveAgr: boolean = false;
  clientKey: SearchResult;
  chartData: ChartOptions = {
    series: [0, 0], // Used & Available Credit
    chart: {
      type: "donut",
      width: 200,
    },
    labels: ["اجمالي الحساب", "المتاح للسحب"],
    colors: ["#ff4560", "#199802"], //  Blue for available, Red for used #ff4560
    tooltip: {
      enabled: true,
    },
    legend: {
      position: "bottom", // Change to "bottom", "top", "left", "right"
    },
  };

  //*paging variables*//
  page: number = 1;
  resultsCount: number;
  totalPages: number = 1;
  pageSize: number = 4;
  @ViewChild("search") search: ClientSearchComponent;
  @ViewChild("transViewSelect") transViewSelect: IonSelect;

  clientSelected(event: SearchResult) {
    this.selectedClient = event;
    this.showLoader = true;
    if (event.client_key != null) {
      this.agreementService
        .getAgreementsByClientKey(event.client_key.toString(), 0)
        .subscribe((response) => {
          if (response.length === 0) {
            return this.alertService.showAlertError(
              "لا يوجد حساب لهذا العميل",
              false
            );
          }
          this.ClientAgreementsResponseModal = response;
          this.isSearching = false;
          this.isAgreementsList = true;
          this.showLoader = false;
        });
    }
  }

  getAgreementInfo(agreement_key: string) {
    if (agreement_key != null) {
      this.showLoader = true;
      this.agreementService
        .getAgreementInfo(agreement_key)
        .subscribe((response) => {
          this.ClientAgreementInfoResponseModal = response;
          this.agreementKey =
            this.ClientAgreementInfoResponseModal[0].agreement_key;
          this.getAgreementTrans(agreement_key, 0);
          this.availableCredit =
            this.ClientAgreementInfoResponseModal[0].available_credit;
          this.creditLimit =
            this.ClientAgreementInfoResponseModal[0].credit_limit;
          if (this.ClientAgreementInfoResponseModal[0].agr_status !== "1") {
            this.isNotActiveAgr = true;
          } else {
            this.isNotActiveAgr = false;
          }
          this.usedBalance = this.creditLimit - this.availableCredit;
          this.chartUpdate();
          this.showLoader = false;
        });
    }
  }

  chartUpdate() {
    this.availableCredit =
      this.ClientAgreementInfoResponseModal[0].available_credit;
    this.creditLimit = this.ClientAgreementInfoResponseModal[0].credit_limit;
    this.chartData = {
      series: [
        Number(Number(this.usedBalance).toFixed(2)),
        Number(Number(this.availableCredit).toFixed(2)),
      ], // Used & Available Credit
      chart: {
        //"donut" | "line" | "area" | "bar" | "histogram" | "pie" | "radialBar" | "scatter" | "bubble" | "heatmap" | "candlestick" | "boxPlot" | "radar" | "polarArea" | "rangeBar" | "rangeArea" | "treemap"
        type: "donut",
        height: "200%",
        width: "200%",
      },
      labels: ["المستخدم", "المتاح للسحب"],
      colors: ["#ff4560", "#199802"], //  Blue for available, Red for used #ff4560
      tooltip: {
        enabled: true,
      },
      legend: {
        position: "bottom", // Change to "bottom", "top", "left", "right"
      },
    };
  }

  transViewSelectHandleChange() {
    this.currentTransType = this.transViewSelect.value;
    switch (this.transViewSelect.value) {
      case 0: {
        this.page = 1;
        this.isCounterCard = true;
        // this.isWithdraw = true;
        // this.isDeposit = true;
        break;
      }
      case 1: {
        this.page = 1;
        this.isCounterCard = true;
        // this.isWithdraw = true;
        // this.isDeposit = false;
        break;
      }
      case 3: {
        this.page = 1;
        this.isCounterCard = true;
        // this.isWithdraw = false;
        // this.isDeposit = true;
        break;
      }
      case 5: {
        this.page = 1;
        this.isCounterCard = false;
        // this.isWithdraw = false;
        // this.isDeposit = false;
        break;
      }
    }
    this.getAgreementTrans(this.agreementKey, this.transViewSelect.value);
  }

  moreOptionsToggleSelect() {
    this.showMoreOptions = !this.showMoreOptions;
  }

  backButt(type: string) {
    switch (type) {
      case "toSearch": {
        this.isAgreementsList = false;
        this.isSearching = true;
        this.ClientAgreementsResponseModal = [];
        this.ClientAgreementInfoResponseModal = [];
        this.ClientAgreementTransResponseModal = [];
        this.agreementKey = " ";
        this.showMoreOptions = false;
        break;
      }
      case "toList": {
        this.transViewSelectInitialValue = 0;
        this.ClientAgreementTransResponseModal = [];
        this.isAgreementsList = true;
        this.isAgreementSelected = false;
        this.ClientAgreementInfoResponseModal = [];
        this.agreementKey = " ";
        this.showMoreOptions = false;
        this.isAgreeHaveNoTrans = false;
        this.page = 1;
        this.clientSelected(this.selectedClient);
        break;
      }
      // default: {
      //    //statements;
      //    break;
      // }
    }
  }

  startCounting() {
    let interval = setInterval(() => {
      if (this.withdrawTransCounter < this.withdrawTransCounter) {
        this.withdrawTransCounter++;
      } else {
        clearInterval(interval);
      }
    }, 1000);
  }

  transTypeChecker() {
    if (this.withdrawTransCounter == 0) {
      this.isWithdraw = false;
    } else {
      this.isWithdraw = true;
    }
    if (this.depositTransCounter == 0) {
      this.isDeposit = false;
    } else {
      this.isDeposit = true;
    }
    if (this.dailyTransCounter == 0) {
      this.isDailyTrns = false;
    } else {
      this.isDailyTrns = true;
    }
  }

  changePaginationPage = async (newPage: number) => {
    this.page = newPage;
    this.getAgreementTrans(this.agreementKey, this.currentTransType);
  };

  getAgreementTrans(agreement_key: string, transType: number) {
    if (agreement_key != null) {
      this.showLoader = true;
      this.isAgreementsList = false;
      this.isAgreementSelected = true;
      this.agreementService
        .getAgreementTransPaging(
          agreement_key,
          this.page,
          this.pageSize,
          transType
        )
        .subscribe((response) => {
          this.ClientAgreementTransResponseModalPaging = response["result"];
          this.resultsCount = response.count;
          let x = response.count / this.pageSize;
          this.totalPages =
            Math.trunc(x) < response.count / this.pageSize
              ? Math.trunc(x) + 1
              : Math.trunc(x);

          if (response.count == 0) {
            this.isAgreeHaveNoTrans = true;
            this.isCounterCard = false;
          } else {
            this.isAgreeHaveNoTrans = false;
            this.isCounterCard = true;
          }
          if (response["result"].length === 0) {
            this.showLoader = false;
            return;
          }
          //filter only withdraw = 1
          this.withdrawTransCounter =
            response["result"][0]["withdrawTransCounter"];
          //filter only deposit = 3
          this.depositTransCounter =
            response["result"][0]["depositTransCounter"];
          //filter only deposit = 5
          this.dailyTransCounter = response["result"][0]["dailyTransCounter"];

          this.transTypeChecker();
          this.showLoader = false;
        });
    }
  }
}
